import{_ as a,c as s,a1 as t,o as e}from"./chunks/framework.BDxlaA_J.js";const u=JSON.parse('{"title":"Hướng dẫn Recon-ng","description":"","frontmatter":{},"headers":[],"relativePath":"vi/categories/ethical-hacking-labs/1-footprinting-and-reconnaissance/3-Recon-ng.md","filePath":"vi/categories/ethical-hacking-labs/1-footprinting-and-reconnaissance/3-Recon-ng.md"}'),p={name:"vi/categories/ethical-hacking-labs/1-footprinting-and-reconnaissance/3-Recon-ng.md"};function c(o,n,i,l,h,r){return e(),s("div",null,n[0]||(n[0]=[t(`<h1 id="huong-dan-recon-ng" tabindex="-1">Hướng dẫn Recon-ng <a class="header-anchor" href="#huong-dan-recon-ng" aria-label="Permalink to &quot;Hướng dẫn Recon-ng&quot;">​</a></h1><p>Recon-ng là công cụ reconnaissance dựa trên web mã nguồn mở, dùng để trích xuất thông tin từ tổ chức mục tiêu và nhân sự của họ. <em>Kho lưu trữ chính thức:</em><a href="https://github.com/lanmaster53/recon-ng" target="_blank" rel="noreferrer">https://github.com/lanmaster53/recon-ng</a></p><ul><li>Phiên bản: v5.0.1</li></ul><h3 id="yeu-cau" tabindex="-1">Yêu cầu: <a class="header-anchor" href="#yeu-cau" aria-label="Permalink to &quot;Yêu cầu:&quot;">​</a></h3><ul><li>Máy ảo Kali Linux</li></ul><h3 id="muc-tieu" tabindex="-1">Mục tiêu: <a class="header-anchor" href="#muc-tieu" aria-label="Permalink to &quot;Mục tiêu:&quot;">​</a></h3><ul><li>Cách thực hiện recon mạng.</li><li>Thu thập các host liên quan đến một tên miền.</li><li>Thu thập thông tin cá nhân.</li><li>Tạo báo cáo với thông tin đã thu thập.</li></ul><p>Recon-ng có giao diện và cách sử dụng tương tự Metasploit Framework, giảm đường cong học tập khi sử dụng framework này.</p><h2 id="cac-buoc-đau-tien" tabindex="-1">Các bước đầu tiên <a class="header-anchor" href="#cac-buoc-đau-tien" aria-label="Permalink to &quot;Các bước đầu tiên&quot;">​</a></h2><ol><li>Mở terminal và gõ <code>recon-ng</code></li><li>Gõ <code>help</code> để xem tất cả các lệnh cho phép bạn thêm/xóa bản ghi vào DB, truy vấn, v.v.</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>back            Thoát khỏi ngữ cảnh hiện tại</span></span>
<span class="line"><span>dashboard       Hiển thị tóm tắt hoạt động</span></span>
<span class="line"><span>db              Giao diện với cơ sở dữ liệu workspace</span></span>
<span class="line"><span>exit            Thoát khỏi framework</span></span>
<span class="line"><span>help            Hiển thị menu này</span></span>
<span class="line"><span>index           Tạo chỉ mục module (chỉ dành cho dev)</span></span>
<span class="line"><span>keys            Quản lý thông tin xác thực tài nguyên bên thứ ba</span></span>
<span class="line"><span>marketplace     Giao diện với marketplace module</span></span>
<span class="line"><span>modules         Giao diện với các module đã cài đặt</span></span>
<span class="line"><span>options         Quản lý tùy chọn ngữ cảnh hiện tại</span></span>
<span class="line"><span>pdb             Khởi chạy phiên Python Debugger (chỉ dành cho dev)</span></span>
<span class="line"><span>script          Ghi và thực thi script lệnh</span></span>
<span class="line"><span>shell           Thực thi lệnh shell</span></span>
<span class="line"><span>show            Hiển thị các mục khác nhau của framework</span></span>
<span class="line"><span>snapshots       Quản lý snapshot workspace</span></span>
<span class="line"><span>spool           Xuất output ra file</span></span>
<span class="line"><span>workspaces      Quản lý workspace</span></span></code></pre></div><p><strong>Lưu ý: Khi tải recon-ng lần đầu, hãy chú ý thông báo dưới đây. Bạn bắt đầu với một framework trống (không có module được cài đặt sẵn).</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[*] No modules enabled/installed.</span></span></code></pre></div><ol start="3"><li><p>Tạo workspace mới: <code>workspaces create CEH</code></p></li><li><p>Thêm tên miền mục tiêu để thực hiện recon mạng: <code>db insert domains</code><code>certifiedhacker.com</code></p></li></ol><p>Bạn có thể xem tên miền đã thêm bằng cách gõ <code>show domains</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[recon-ng][CEH] &gt; db insert domains</span></span>
<span class="line"><span>domain (TEXT): certifiedhacker.com</span></span>
<span class="line"><span>[*] 1 rows affected.</span></span>
<span class="line"><span>[recon-ng][CEH] &gt; show domains</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  +--------------------------------------------+</span></span>
<span class="line"><span>  | rowid |        domain       |    module    |</span></span>
<span class="line"><span>  +--------------------------------------------+</span></span>
<span class="line"><span>  | 1     | certifiedhacker.com | user_defined |</span></span>
<span class="line"><span>  +--------------------------------------------+</span></span></code></pre></div><h2 id="su-dung-module-tu-recon-ng-marketplace" tabindex="-1">Sử dụng Module từ Recon-ng Marketplace <a class="header-anchor" href="#su-dung-module-tu-recon-ng-marketplace" aria-label="Permalink to &quot;Sử dụng Module từ Recon-ng Marketplace&quot;">​</a></h2><p>Recon-ng hoạt động với các module độc lập, tương tác cơ sở dữ liệu, các hàm tiện ích tích hợp sẵn, trợ giúp tương tác và hoàn thành lệnh, Recon-ng cung cấp một môi trường mạnh mẽ để thực hiện reconnaissance dựa trên web mã nguồn mở một cách nhanh chóng và toàn diện. Để thêm module mới, bạn sẽ sử dụng <strong>marketplace</strong>.</p><p>Kho lưu trữ Recon-ng Marketplace: <a href="https://github.com/lanmaster53/recon-ng-marketplace" target="_blank" rel="noreferrer">https://github.com/lanmaster53/recon-ng-marketplace</a></p><p>Để xem toàn bộ marketplace repo, gõ: <code>marketplace search</code></p><p>Quy trình làm việc với module và workspace rất đơn giản như ví dụ dưới đây:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>0. Cài đặt module bằng lệnh marketplace:</span></span>
<span class="line"><span>&gt; marketplace install recon/domains-hosts/findsubdomains</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. Tải module bằng lệnh modules load:</span></span>
<span class="line"><span>&gt; modules load /recon/domains-hosts/findsubdomains</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. Để hiển thị tùy chọn module:</span></span>
<span class="line"><span>&gt; info</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. Thực thi module:</span></span>
<span class="line"><span>&gt; run</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. Để chuyển đổi giữa các module hoặc workspace, gõ:</span></span>
<span class="line"><span>&gt; back</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5. Chọn workspace hiện có:</span></span>
<span class="line"><span>&gt; workspaces select W0rkspaceName</span></span>
<span class="line"><span></span></span>
<span class="line"><span>6. Chọn module đã cài đặt:</span></span>
<span class="line"><span>&gt; modules load path/to/module-name</span></span></code></pre></div><h2 id="su-dung-hackertarget-đe-tim-sub-domain" tabindex="-1">Sử dụng hackertarget để tìm sub-domain <a class="header-anchor" href="#su-dung-hackertarget-đe-tim-sub-domain" aria-label="Permalink to &quot;Sử dụng hackertarget để tìm sub-domain&quot;">​</a></h2><p>Bạn có thể tìm các module khác để thu thập subdomain, chúng ta sẽ sử dụng hackertarget trong hướng dẫn này.</p><p>Hãy cài đặt và tải nó: <code>marketplace install hackertarget</code><code>modules load hackertarget</code></p><p>Gõ <code>info</code> để xem SOURCE, hiện đang được đặt mặc định như bên dưới: <code>info</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Name    Current Value  Required  Description</span></span>
<span class="line"><span>------  -------------  --------  -----------</span></span>
<span class="line"><span>SOURCE  default        yes       source of input (see &#39;show info&#39; for details)</span></span></code></pre></div><p>Bây giờ đặt SOURCE thành:</p><p><code>options set SOURCE certifiedhacker.com</code></p><p>Bạn có thể sử dụng lệnh <code>input</code> để xem mục tiêu:</p><p><code>input</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>+---------------------+</span></span>
<span class="line"><span>|    Module Inputs    |</span></span>
<span class="line"><span>+---------------------+</span></span>
<span class="line"><span>| certifiedhacker.com |</span></span>
<span class="line"><span>+---------------------+</span></span></code></pre></div><p>Chạy module:</p><p><code>run</code></p><p><strong>Lưu ý: Nếu phản hồi của bạn hoạt động đúng nhưng lộn xộn với nhiều truy vấn và giá trị, chỉ cần gõ <code>show hosts</code> để hiển thị output tốt hơn.</strong></p><p><code>show hosts</code> ... <em>(Lệnh này sẽ hiển thị tóm tắt gọn gàng về các tài nguyên đã khám phá)</em></p><h2 id="brute-force-ten-host" tabindex="-1">Brute-force tên host <a class="header-anchor" href="#brute-force-ten-host" aria-label="Permalink to &quot;Brute-force tên host&quot;">​</a></h2><p>Bạn có thể sử dụng các module khác để thu thập thêm host, chẳng hạn như <strong>brute_hosts</strong>.</p><p><strong>Thoát</strong> khỏi module hiện tại:</p><p><code>back</code></p><p>Cài đặt module <strong>brute_hosts</strong>:</p><p><code>marketplace install recon/domain-hosts/brute_hosts</code></p><p>Tải module:</p><p><code>modules load recon/domain-hosts/brute_hosts</code></p><p>Đặt SOURCE thành tên miền mục tiêu:</p><p><code>options set SOURCE certifiedhacker.com</code></p><p>Bằng cách gõ <code>info</code>, bạn có thể thấy trong module cụ thể này, bạn có thể đặt wordlist hostname của riêng mình. Tôi khuyến nghị sử dụng wordlist mặc định vì nó khá tốt.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Name      Current Value</span></span>
<span class="line"><span>  --------  -------------</span></span>
<span class="line"><span>  SOURCE    certifiedhacker.com</span></span>
<span class="line"><span>  WORDLIST  /root/.recon-ng/data/hostnames.txt</span></span></code></pre></div><ol start="5"><li>Chạy module: <code>run</code> ... <em>(lưu ý rằng quá trình này sẽ mất một lúc)</em></li></ol><h2 id="tao-bao-cao" tabindex="-1">Tạo báo cáo <a class="header-anchor" href="#tao-bao-cao" aria-label="Permalink to &quot;Tạo báo cáo&quot;">​</a></h2><p>Bây giờ bạn đã thu thập được một số host, bạn sẽ chuẩn bị một báo cáo chứa tất cả thông tin.</p><p>Cài đặt <strong>reporting module</strong> để xuất báo cáo định dạng html.</p><p><code>marketplace install reporting/html</code></p><p><strong>Lưu ý:</strong> Bạn có thể cài đặt bất kỳ module nào dưới đây để xuất ở các định dạng khác nhau.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>reporting/csv</span></span>
<span class="line"><span>reporting/html</span></span>
<span class="line"><span>reporting/json</span></span>
<span class="line"><span>reporting/list</span></span>
<span class="line"><span>reporting/proxifier</span></span>
<span class="line"><span>reporting/pushpin</span></span>
<span class="line"><span>reporting/xlsx</span></span>
<span class="line"><span>reporting/xml</span></span></code></pre></div><p>Tải module:</p><p><code>modules load reporting/html</code></p><p>Để cấu hình thông tin báo cáo, gõ <code>info</code> để xem các giá trị.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span> Name      Current Value</span></span>
<span class="line"><span> --------  -------------</span></span>
<span class="line"><span> CREATOR</span></span>
<span class="line"><span> CUSTOMER</span></span>
<span class="line"><span> FILENAME  /root/.recon-ng/workspaces/CEH/results.html</span></span>
<span class="line"><span> SANITIZE  True</span></span></code></pre></div><p>Bạn sẽ cần gán các giá trị này: CREATOR, CUSTOMER và FILENAME.</p><p>Đặt tên của bạn [CREATOR], tên khách hàng [CUSTOMER], đường dẫn xuất và tên file [FILENAME].</p><p><code>options set CREATOR J0nDoe</code><code>options set CUSTOMER CertifiedHacker Network</code><code>options set FILENAME /root/Desktop/CE-Results.html</code></p><p>Chạy module để xuất:</p><p><code>run</code></p><p><strong>Báo cáo được tạo sẽ lưu vào Desktop.</strong></p><p>Không có nhiều nội dung trong báo cáo này, nhưng khi bạn bắt đầu chạy nhiều module và thêm báo cáo geolocation, nó có thể trở nên rất phức tạp. Recon-ng làm rất tốt việc theo dõi tất cả mọi thứ.</p><h1 id="su-dung-recon-ng-đe-thu-thap-thong-tin-nhan-su-phan-2" tabindex="-1">Sử dụng Recon-ng để thu thập thông tin nhân sự (phần 2) <a class="header-anchor" href="#su-dung-recon-ng-đe-thu-thap-thong-tin-nhan-su-phan-2" aria-label="Permalink to &quot;Sử dụng Recon-ng để thu thập thông tin nhân sự (phần 2)&quot;">​</a></h1><p>Mục tiêu:</p><ul><li>Lấy thông tin liên hệ của nhân viên làm việc trong một tổ chức.</li><li>Tìm sự tồn tại của hồ sơ người dùng trên nhiều trang web khác nhau.</li></ul><p><strong>Lưu ý quan trọng:</strong> Các module <strong>location</strong> và <strong>pushpin</strong> được đề cập trong hướng dẫn này yêu cầu khóa API hợp lệ để sử dụng và có một số vấn đề liên quan đến GDPR về thu thập dữ liệu. Một số yêu cầu bạn phải trả tiền, sẽ được đề cập bên dưới. Tôi khuyên bạn nên lưu tất cả các khóa API vào một file để có thể sử dụng sau này. Để thiết lập khóa API cho recon-ng rất đơn giản, chỉ cần làm theo tài liệu bên dưới và quản lý khóa bên trong Recon-ng bằng lệnh: <code>keys</code>. <a href="https://github.com/Raikia/Recon-NG-API-Key-Creation/blob/master/README-v4.8.3.md" target="_blank" rel="noreferrer">https://github.com/Raikia/Recon-NG-API-Key-Creation/blob/master/README-v4.8.3.md</a></p><h2 id="thu-thap-thong-tin-ca-nhan" tabindex="-1">Thu thập thông tin cá nhân <a class="header-anchor" href="#thu-thap-thong-tin-ca-nhan" aria-label="Permalink to &quot;Thu thập thông tin cá nhân&quot;">​</a></h2><p>Thu thập thông tin cá nhân bao gồm khám phá thông tin liên hệ như email, địa chỉ, v.v. hiện diện trên trang web của tổ chức mục tiêu. Recon-ng chứa nhiều module để thu thập và khám phá thông tin liên hệ về một công ty nhất định. Một số module Recon-ng để khám phá thông tin cá nhân là:</p><ul><li>recon/domain-contacts</li><li>recon/companies-contacts</li><li>recon/domain-contacts/namechk</li></ul><h2 id="thiet-lap-recon-ng" tabindex="-1">Thiết lập Recon-ng <a class="header-anchor" href="#thiet-lap-recon-ng" aria-label="Permalink to &quot;Thiết lập Recon-ng&quot;">​</a></h2><ol><li>Khởi động Kali Linux và mở terminal.</li><li>Gõ <code>recon-ng</code> để khởi chạy ứng dụng.</li><li>Thêm workspace mới tên là recon:</li></ol><p><code>workspaces create recon</code></p><h2 id="thu-thap-thong-tin-lien-he-lien-ket-voi-mot-ten-mien" tabindex="-1">Thu thập thông tin liên hệ liên kết với một tên miền <a class="header-anchor" href="#thu-thap-thong-tin-lien-he-lien-ket-voi-mot-ten-mien" aria-label="Permalink to &quot;Thu thập thông tin liên hệ liên kết với một tên miền&quot;">​</a></h2><p>Đặt tên miền và thực hiện footprinting trên đó để trích xuất thông tin liên hệ có sẵn trong tên miền.</p><p>Module được chọn để thực hiện kỹ thuật này sử dụng ARIN Whois RWS để thu thập dữ liệu POC từ các truy vấn whois cho tên miền nhất định.</p><p>Cài đặt và tải module:</p><p><code>marketplace install recon/domains-contacts/whois_pocs</code></p><p><code>modules load recon/domains-contacts/whois_pocs</code></p><p>Kiểm tra các tùy chọn cần thiết để chạy module:</p><p><code>info</code></p><p>Đặt giá trị SOURCE thành tên miền mục tiêu:</p><p><code>options set SOURCE facebook.com</code></p><p>Chạy module:</p><p><code>run</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>------------</span></span>
<span class="line"><span>FACEBOOK.COM</span></span>
<span class="line"><span>------------</span></span>
<span class="line"><span>[*] URL: http://whois.arin.net/rest/pocs;domain=facebook.com</span></span>
<span class="line"><span>[*] URL: http://whois.arin.net/rest/poc/NOL17-ARIN</span></span>
<span class="line"><span>[*] [contact] Lea Neteork ops (leigha311@facebook.com) - Whois contact</span></span>
<span class="line"><span>[*] URL: http://whois.arin.net/rest/poc/OPERA82-ARIN</span></span>
<span class="line"><span>[*] [contact] &lt;blank&gt; Operations (domain@facebook.com) - Whois contact</span></span>
<span class="line"><span>[*] URL: http://whois.arin.net/rest/poc/BST184-ARIN</span></span>
<span class="line"><span>[*] [contact] Brandon Stout (bstout@facebook.com) - Whois contact</span></span>
<span class="line"><span>[*] URL: http://whois.arin.net/rest/poc/DJW23-ARIN</span></span>
<span class="line"><span>[*] [contact] Darrell Wayne (tiffany.cameron.507@facebook.com) - Whois contact</span></span>
<span class="line"><span>[*] URL: http://whois.arin.net/rest/poc/MZU-ARIN</span></span>
<span class="line"><span>[*] [contact] Mark Zuckerberg (zuck@thefacebook.com) - Whois contact</span></span></code></pre></div><p>Kết quả sẽ trả về các thông tin liên hệ liên quan đến tên miền.</p><h2 id="su-ton-tai-ho-so" tabindex="-1">Sự tồn tại hồ sơ <a class="header-anchor" href="#su-ton-tai-ho-so" aria-label="Permalink to &quot;Sự tồn tại hồ sơ&quot;">​</a></h2><p>Module <strong>recon/profiles-profiles/namechk</strong> xác minh sự tồn tại của tên người dùng của một liên hệ cụ thể, nhưng đáng tiếc namechk tính phí để sử dụng API của họ.</p><p>Chúng ta có thể tìm kiếm sự tồn tại của hồ sơ người dùng trên nhiều trang web khác nhau bằng module <strong>recon/profiles-profiles/profiler</strong>.</p><p>Gõ <code>back</code> để quay về trang chủ workspace.</p><p>Cài đặt và tải module:</p><p><code>marketplace install recon/profiles-profiles/profiler</code></p><p><code>modules load recon/profiles-profiles/profiler</code></p><p>Đặt giá trị SOURCE (Tên người dùng mục tiêu):</p><p><code>options set SOURCE MarkZuckerberg</code></p><p>Chạy module:</p><p><code>run</code></p><p>Module recon/profiles-profiles/profiler tìm kiếm tên người dùng này và trả về URL của hồ sơ trên nhiều trang web khác nhau (tìm thấy với tên người dùng trùng khớp).</p>`,102)]))}const g=a(p,[["render",c]]);export{u as __pageData,g as default};
